    /// locale: ms_409 <br/>
    ///  <br/>
    /// provider: CIMWin32 <br/>
    ///  <br/>
    /// uuid: {8502C4CC-5FBB-11D2-AAC1-006008C78BC7} <br/>
    ///  <br/>
    /// </summary>
    public class Win32_UserAccount
    {
        /// <summary>
        /// The AccountType property contains flags describing the characteristics of Win32 user account: <br/>
        /// UF_TEMP_DUPLICATE_ACCOUNT - Local user account for users whose primary account is in another domain. <br/>
        /// This account provides user access to this domain, but not to any domain that trusts this domain. <br/>
        /// UF_NORMAL_ACCOUNT - default account type that representing a typical user. <br/>
        /// UF_INTERDOMAIN_TRUST_ACCOUNT - account is for a system domain that trusts other domains. <br/>
        /// UF_WORKSTATION_TRUST_ACCOUNT - This is a computer account for a Windows NT/Windows 2000 machine that is a member of this domain. <br/>
        /// UF_SERVER_TRUST_ACCOUNT - account is for a system backup domain controller that is a member of this domain. <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 AccountType { get; set; }
        /// <summary>
        /// The Caption property is a short textual description (one-line string) of the object. <br/>
        ///  <br/>
        /// cimtype: string <br/>
        ///  <br/>
        /// </summary>
        public String Caption { get; set; }
        /// <summary>
        /// The Description property provides a textual description of the object. <br/>
        ///  <br/>
        /// cimtype: string <br/>
        ///  <br/>
        /// </summary>
        public String Description { get; set; }
        /// <summary>
        /// The Disabled property determines whether the Win32 user account is disabled. <br/>
        /// Values: TRUE or FALSE. <br/>
        /// If TRUE, the user account is disabled. <br/>
        ///  <br/>
        /// cimtype: boolean <br/>
        ///  <br/>
        /// </summary>
        public Boolean Disabled { get; set; }
        /// <summary>
        /// The Domain property indicates the name of the Windows domain to which the user account belongs. <br/>
        /// Example: NA-SALES <br/>
        ///  <br/>
        /// cimtype: string <br/>
        ///  <br/>
        /// override: Domain <br/>
        ///  <br/>
        /// </summary>
        public String Domain { get; set; }
        /// <summary>
        /// The FullName property indicates the full name of the local user. <br/>
        /// Example: Thomas Williams <br/>
        ///  <br/>
        /// cimtype: string <br/>
        ///  <br/>
        /// </summary>
        public String FullName { get; set; }
        /// <summary>
        /// The InstallDate property is datetime value indicating when the object was installed. <br/>
        /// A lack of a value does not indicate that the object is not installed. <br/>
        ///  <br/>
        /// cimtype: datetime <br/>
        ///  <br/>
        /// </summary>
        public DateTime InstallDate { get; set; }
        /// <summary>
        /// The LocalAccount property indicates whether the account is defined on the local machine. <br/>
        /// To retrieve only accounts defined on the local machine state a query that includes the condition &apos;LocalAccount=TRUE&apos;. <br/>
        ///  <br/>
        /// cimtype: Boolean <br/>
        ///  <br/>
        /// </summary>
        public Boolean LocalAccount { get; set; }
        /// <summary>
        /// The Lockout property determines whether the user account is locked out of the Win32 system. <br/>
        /// Values: TRUE or FALSE. <br/>
        /// If TRUE, the user account is locked out. <br/>
        ///  <br/>
        /// cimtype: boolean <br/>
        ///  <br/>
        /// </summary>
        public Boolean Lockout { get; set; }
        /// <summary>
        /// The Name property indicates the name of the Win32 user account on the domain specified by the Domain member of this class. <br/>
        /// Example: thomasw <br/>
        ///  <br/>
        /// cimtype: string <br/>
        ///  <br/>
        /// override: Name <br/>
        ///  <br/>
        /// </summary>
        public String Name { get; set; }
        /// <summary>
        /// The PasswordChangeable property determines whether the password on the Win32 user account can be changed. <br/>
        /// Values: TRUE or FALSE. <br/>
        /// If TRUE, the password can be changed. <br/>
        ///  <br/>
        /// cimtype: boolean <br/>
        ///  <br/>
        /// </summary>
        public Boolean PasswordChangeable { get; set; }
        /// <summary>
        /// The PasswordExpires property determines whether the password on the Win32 user account will expire. <br/>
        /// Values: TRUE or FALSE. <br/>
        /// If TRUE, the password will expire. <br/>
        ///  <br/>
        /// cimtype: boolean <br/>
        ///  <br/>
        /// </summary>
        public Boolean PasswordExpires { get; set; }
        /// <summary>
        /// The PasswordRequired property determines whether a password is required on the Win32 user account. <br/>
        /// Values: TRUE or FALSE. <br/>
        /// If TRUE, a password is required. <br/>
        ///  <br/>
        /// cimtype: boolean <br/>
        ///  <br/>
        /// </summary>
        public Boolean PasswordRequired { get; set; }
        /// <summary>
        /// The SID property contains the security identifier (SID) for this account. <br/>
        /// a SID is a string value of variable length used to identify a trustee. <br/>
        /// Each account has a unique SID issued by an authority (such as a Windows domain), stored in a security database. <br/>
        /// When a user logs on, the system retrieves the user&apos;s SID from the database and places it in the user&apos;s access token. <br/>
        /// The system uses the SID in the user&apos;s access token to identify the user in all subsequent interactions with Windows security. <br/>
        /// When a SID has been used as the unique identifier for a user or group, it cannot be used again to identify another user or group. <br/>
        ///  <br/>
        /// cimtype: string <br/>
        ///  <br/>
        /// </summary>
        public String SID { get; set; }
        /// <summary>
        /// The SIDType property contains enumerated values that specify the type of security identifier (SID). <br/>
        /// SIDTypes include: <br/>
        /// SidTypeUser - Indicates a user SID. <br/>
        /// SidTypeGroup - Indicates a group SID. <br/>
        /// SidTypeDomain - Indicates a domain SID. <br/>
        /// SidTypeAlias - Indicates an alias SID. <br/>
        /// SidTypeWellKnownGroup - Indicates a SID for a well-known group. <br/>
        /// SidTypeDeletedAccount - Indicates a SID for a deleted account. <br/>
        /// SidTypeInvalid - Indicates an invalid SID. <br/>
        /// SidTypeUnknown - Indicates an unknown SID type. <br/>
        /// SidTypeComputer - Indicates a SID for a computer. <br/>
        ///  <br/>
        /// cimtype: uint8 <br/>
        ///  <br/>
        /// </summary>
        public byte SIDType { get; set; }
        /// <summary>
        /// The Status property is a string indicating the current status of the object. <br/>
        /// Various operational and non-operational statuses can be defined. <br/>
        /// Operational statuses are &quot;OK&quot;, &quot;Degraded&quot; and &quot;Pred Fail&quot;. <br/>
        /// &quot;Pred Fail&quot; indicates that an element may be functioning properly but predicting a failure in the near future. <br/>
        /// An example is a SMART-enabled hard drive. <br/>
        /// Non-operational statuses can also be specified. <br/>
        /// These are &quot;Error&quot;, &quot;Starting&quot;, &quot;Stopping&quot; and &quot;Service&quot;. <br/>
        /// The latter, &quot;Service&quot;, could apply during mirror-resilvering of a disk, reload of a user permissions list, or other administrative work. <br/>
        /// Not all such work is on-line, yet the managed element is neither &quot;OK&quot; nor in one of the other states. <br/>
        ///  <br/>
        /// cimtype: string <br/>
        ///  <br/>
        /// </summary>
        public String Status { get; set; }
    }

    /// <summary>
    /// Describes an instance in time as returned by Win32ClockProvider. <br/>
    /// When a query is submitted to the Win32UTCClockProvider, the results are returned as Win32_UTCTime objects with times matching the query. <br/>
    /// These are returned as part of __InstanceModificationEvents <br/>
    ///  <br/>
    /// provider: Win32ClockProvider <br/>
    ///  <br/>
    /// </summary>
    public class Win32_UTCTime
    {
        /// <summary>
        /// The current matching day (1-31) <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 Day { get; set; }
        /// <summary>
        /// The current matching day of the current week (0-6, Sunday being 0) <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 DayOfWeek { get; set; }
        /// <summary>
        /// The current hour of the current day (0-23) <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 Hour { get; set; }
        /// <summary>
        /// (currently not used) <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 Milliseconds { get; set; }
        /// <summary>
        /// The current minute (0-59) <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 Minute { get; set; }
        /// <summary>
        /// The current matching month (1-12) <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 Month { get; set; }
        /// <summary>
        /// The current quarter of the current year (1-4) <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 Quarter { get; set; }
        /// <summary>
        /// The current second of the current minute (0-59) <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 Second { get; set; }
        /// <summary>
        /// The current week in the current month (1-6) <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 WeekInMonth { get; set; }
        /// <summary>
        /// The current matching year (4 digits) <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 Year { get; set; }
    }

    /// <summary>
    /// The Win32_USBControllerDevice class represents an association between a Universal Serial Bus (USB) controller and the CIM_LogicalDevice connected to it. <br/>
    ///  <br/>
    /// locale: ms_409 <br/>
    ///  <br/>
    /// provider: CIMWin32 <br/>
    ///  <br/>
    /// uuid: {DE57D792-A032-11D2-90F0-0060081A46FD} <br/>
    ///  <br/>
    /// </summary>
    public class Win32_USBControllerDevice
    {
        /// <summary>
        /// The AccessState property indicates whether the controller is actively commanding or accessing the device (value=1) or not (value=2). <br/>
        /// Also, the value, &quot;Unknown&quot; (0), can be defined. <br/>
        /// This information is necessary when a logical device can be commanded by, or accessed through, multiple controllers. <br/>
        ///  <br/>
        /// cimtype: uint16 <br/>
        ///  <br/>
        /// </summary>
        public UInt16 AccessState { get; set; }
        /// <summary>
        /// When several bus and/or connection data widths are possible, the NegotiatedDataWidth property defines the one in use between the devices. <br/>
        /// Data width is specified in bits. <br/>
        /// If data width is not negotiated, or if this information is not available/important to device management, the property should be set to 0. <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// units: bits <br/>
        ///  <br/>
        /// </summary>
        public UInt32 NegotiatedDataWidth { get; set; }
        /// <summary>
        /// When several bus and/or connection speeds are possible, the NegotiatedSpeed property defines the one in use between the devices. <br/>
        /// Speed is specified in bits per second. <br/>
        /// If connection or bus speeds are not negotiated, or if this information is not available/important to device management, the property should be set to 0. <br/>
        ///  <br/>
        /// cimtype: uint64 <br/>
        ///  <br/>
        /// units: bits per second <br/>
        ///  <br/>
        /// </summary>
        public UInt64 NegotiatedSpeed { get; set; }
        /// <summary>
        /// Number of hard resets issued by the controller. <br/>
        /// A hard reset returns the device to its initialization or &apos;boot-up&apos; state. <br/>
        /// All internal device state information and data are lost. <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 NumberOfHardResets { get; set; }
        /// <summary>
        /// Number of soft resets issued by the controller. <br/>
        /// A soft reset does not completely clear current device state and/or data. <br/>
        /// Exact semantics are dependent on the device, and on the protocols and mechanisms used to communicate to it. <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 NumberOfSoftResets { get; set; }
    }

