    /// <summary>
    /// The Win32_UserProfile class contains information about user profiles on a Windows system. <br/>
    ///  <br/>
    /// provider: UserProfileProvider <br/>
    ///  <br/>
    /// </summary>
    public class Win32_UserProfile
    {
        /// <summary>
        /// A Win32_FolderRedirectionHealth object that represents the health of the user&apos;s redirected AppData\Roaming folder. <br/>
        ///  <br/>
        /// cimtype: object:Win32_FolderRedirectionHealth <br/>
        ///  <br/>
        /// </summary>
        public Object AppDataRoaming { get; set; }
        /// <summary>
        /// A Win32_FolderRedirectionHealth object that represents the health of the user&apos;s redirected Contacts folder. <br/>
        ///  <br/>
        /// cimtype: object:Win32_FolderRedirectionHealth <br/>
        ///  <br/>
        /// </summary>
        public Object Contacts { get; set; }
        /// <summary>
        /// A Win32_FolderRedirectionHealth object that represents the health of the user&apos;s redirected Desktop folder. <br/>
        ///  <br/>
        /// cimtype: object:Win32_FolderRedirectionHealth <br/>
        ///  <br/>
        /// </summary>
        public Object Desktop { get; set; }
        /// <summary>
        /// A Win32_FolderRedirectionHealth object that represents the health of the user&apos;s redirected Documents folder. <br/>
        ///  <br/>
        /// cimtype: object:Win32_FolderRedirectionHealth <br/>
        ///  <br/>
        /// </summary>
        public Object Documents { get; set; }
        /// <summary>
        /// A Win32_FolderRedirectionHealth object that represents the health of the user&apos;s redirected Downloads folder. <br/>
        ///  <br/>
        /// cimtype: object:Win32_FolderRedirectionHealth <br/>
        ///  <br/>
        /// </summary>
        public Object Downloads { get; set; }
        /// <summary>
        /// A Win32_FolderRedirectionHealth object that represents the health of the user&apos;s redirected Favorites folder. <br/>
        ///  <br/>
        /// cimtype: object:Win32_FolderRedirectionHealth <br/>
        ///  <br/>
        /// </summary>
        public Object Favorites { get; set; }
        /// <summary>
        /// The health status of this profile, based on the values that were set in the Win32_RoamingUserHealthConfiguration properties. <br/>
        ///  <br/>
        /// cimtype: uint8 <br/>
        ///  <br/>
        /// </summary>
        public byte HealthStatus { get; set; }
        /// <summary>
        /// If the profile is a roaming profile, this property is a DATETIME value that indicates the last time an attempt was made to download the profile from the server, even if it was unsuccessful. <br/>
        /// If the profile is a local profile, this property is zero. <br/>
        ///  <br/>
        /// cimtype: DATETIME <br/>
        ///  <br/>
        /// </summary>
        public DateTime LastAttemptedProfileDownloadTime { get; set; }
        /// <summary>
        /// If the profile is a roaming profile, this property is a DATETIME value that indicates the last time an attempt was made to upload the profile to the server, even if it was unsuccessful. <br/>
        ///  <br/>
        /// cimtype: DATETIME <br/>
        ///  <br/>
        /// </summary>
        public DateTime LastAttemptedProfileUploadTime { get; set; }
        /// <summary>
        /// If this profile is a roaming profile, this property is a DATETIME value that indicates the last time the profile&apos;s registry hive was uploaded to the server. <br/>
        ///  <br/>
        /// cimtype: DATETIME <br/>
        ///  <br/>
        /// </summary>
        public DateTime LastBackgroundRegistryUploadTime { get; set; }
        /// <summary>
        /// This property indicates when a roaming profile was downloaded from server last time. <br/>
        ///  <br/>
        /// cimtype: DATETIME <br/>
        ///  <br/>
        /// </summary>
        public DateTime LastDownloadTime { get; set; }
        /// <summary>
        /// This property indicates when a roaming profile was uploaded to server last time. <br/>
        ///  <br/>
        /// cimtype: DATETIME <br/>
        ///  <br/>
        /// </summary>
        public DateTime LastUploadTime { get; set; }
        /// <summary>
        /// This property indicates when this profile is used last time. <br/>
        ///  <br/>
        /// cimtype: DATETIME <br/>
        ///  <br/>
        /// </summary>
        public DateTime LastUseTime { get; set; }
        /// <summary>
        /// A Win32_FolderRedirectionHealth object that represents the health of the user&apos;s redirected Links folder. <br/>
        ///  <br/>
        /// cimtype: object:Win32_FolderRedirectionHealth <br/>
        ///  <br/>
        /// </summary>
        public Object Links { get; set; }
        /// <summary>
        /// This property indicates whether this profile is loaded. <br/>
        ///  <br/>
        /// cimtype: boolean <br/>
        ///  <br/>
        /// </summary>
        public Boolean Loaded { get; set; }
        /// <summary>
        /// This property contains the user profile&apos;s path on the local computer. <br/>
        ///  <br/>
        /// cimtype: string <br/>
        ///  <br/>
        /// </summary>
        public String LocalPath { get; set; }
        /// <summary>
        /// A Win32_FolderRedirectionHealth object that represents the health of the user&apos;s redirected Music folder. <br/>
        ///  <br/>
        /// cimtype: object:Win32_FolderRedirectionHealth <br/>
        ///  <br/>
        /// </summary>
        public Object Music { get; set; }
        /// <summary>
        /// A Win32_FolderRedirectionHealth object that represents the health of the user&apos;s redirected Pictures folder. <br/>
        ///  <br/>
        /// cimtype: object:Win32_FolderRedirectionHealth <br/>
        ///  <br/>
        /// </summary>
        public Object Pictures { get; set; }
        /// <summary>
        /// This property indicates the ref count of the profile. <br/>
        /// If the profile is loaded, the ref count is at least 1. <br/>
        /// Higher values indicates there are more than one applications or services has loaded the profile and using it. <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 RefCount { get; set; }
        /// <summary>
        /// This property indicates whether the user has a roaming profile configured. <br/>
        /// NOTE: User has a roaming profile configured does not mean that this profile is indeed roaming. <br/>
        /// There are other policies and user preference can prevent the profile from roaming. <br/>
        /// Please refer to the RoamingPreference and Status property. <br/>
        ///  <br/>
        /// cimtype: boolean <br/>
        ///  <br/>
        /// </summary>
        public Boolean RoamingConfigured { get; set; }
        /// <summary>
        /// This property contains the user&apos;s roaming profile path if RoamingConfigured is true. <br/>
        ///  <br/>
        /// cimtype: string <br/>
        ///  <br/>
        /// </summary>
        public String RoamingPath { get; set; }
        /// <summary>
        /// This property indicates whether the user prefer to roam this profile if RoamingConfigured is true. <br/>
        /// By default, this property will be true to let the roaming profile roam between the local computer and the server. <br/>
        /// User can set this property to false to prevent roaming, then the profile will work like a local profile. <br/>
        ///  <br/>
        /// cimtype: boolean <br/>
        ///  <br/>
        /// </summary>
        public Boolean RoamingPreference { get; set; }
        /// <summary>
        /// A Win32_FolderRedirectionHealth object that represents the health of the user&apos;s redirected Saved Games folder. <br/>
        ///  <br/>
        /// cimtype: object:Win32_FolderRedirectionHealth <br/>
        ///  <br/>
        /// </summary>
        public Object SavedGames { get; set; }
        /// <summary>
        /// A Win32_FolderRedirectionHealth object that represents the health of the user&apos;s redirected Searches folder. <br/>
        ///  <br/>
        /// cimtype: object:Win32_FolderRedirectionHealth <br/>
        ///  <br/>
        /// </summary>
        public Object Searches { get; set; }
        /// <summary>
        /// This property contains the SID of the user who owns this user profile. <br/>
        ///  <br/>
        /// cimtype: string <br/>
        ///  <br/>
        /// </summary>
        public String SID { get; set; }
        /// <summary>
        /// This property indicates whether this profile belongs to a special system service. <br/>
        ///  <br/>
        /// cimtype: boolean <br/>
        ///  <br/>
        /// </summary>
        public Boolean Special { get; set; }
        /// <summary>
        /// A Win32_FolderRedirectionHealth object that represents the health of the user&apos;s redirected Start Menu folder. <br/>
        ///  <br/>
        /// cimtype: object:Win32_FolderRedirectionHealth <br/>
        ///  <br/>
        /// </summary>
        public Object StartMenu { get; set; }
        /// <summary>
        /// May be one or more of the following: <br/>
        /// 0x00000001 - Indicate the profile is a temporary profile, it will be deleted at user logoff. <br/>
        /// 0x00000002 - Indicate the profile is now set to roaming, if this bit is not set, then it is set to local. <br/>
        /// 0x00000004 - Indicate the profile is a mandatory profile. <br/>
        /// 0x00000008 - Indicate the profile is a corrupted profile, and not in use, user or administrator must fix <br/>
        /// the corruption in order to use this profile again. <br/>
        ///  <br/>
        /// cimtype: uint32 <br/>
        ///  <br/>
        /// </summary>
        public UInt32 Status { get; set; }
        /// <summary>
        /// A Win32_FolderRedirectionHealth object that represents the health of the user&apos;s redirected Videos folder. <br/>
        ///  <br/>
        /// cimtype: object:Win32_FolderRedirectionHealth <br/>
        ///  <br/>
        /// </summary>
        public Object Videos { get; set; }
    }

